INSERT INTO quiz_questions (event_id, topic, subtopic, question, options, correct_index, correct_answer_text, explanation, difficulty, question_type, points, source_tournament, ai_generated)
VALUES
  ((SELECT id FROM events WHERE name = 'Ecology'), 'Metabolic Theory', NULL, 'The metabolic theory of ecology suggests that metabolic rates scale with body mass according to what exponent?', '["1.0", "-1.5", "-0.75", "0.25"]'::jsonb, 2, '-0.75', NULL, 'hard', 'multiple_choice', 1, 'Badger Invitational 2025', false),
  ((SELECT id FROM events WHERE name = 'Ecology'), 'Competition Models', NULL, 'In Lotka-Volterra competition models, what does a competition coefficient (α) greater than 1 indicate?', '["Intraspecific competition is stronger than interspecific competition", "Interspecific competition is stronger than intraspecific competition", "The populations are at equilibrium", "The species cannot coexist"]'::jsonb, 1, 'Interspecific competition is stronger than intraspecific competition', NULL, 'hard', 'multiple_choice', 1, 'Badger Invitational 2025', false),
  ((SELECT id FROM events WHERE name = 'Ecology'), 'Energy Flow', NULL, 'According to the Lindeman efficiency rule, approximately what percentage of energy is transferred between trophic levels?', '["50%", "10%", "25%", "1%"]'::jsonb, 1, '10%', NULL, 'medium', 'multiple_choice', 1, 'Badger Invitational 2025', false),
  ((SELECT id FROM events WHERE name = 'Ecology'), 'Survivorship Curves', NULL, 'Which of the following is a defining characteristic of a Type III survivorship curve?', '["High survival in early life stages, declining in later stages", "Constant mortality throughout life", "High mortality in early life, with survival increasing for older individuals", "Equal mortality across all age groups"]'::jsonb, 2, 'High mortality in early life, with survival increasing for older individuals', NULL, 'medium', 'multiple_choice', 1, 'Badger Invitational 2025', false),
  ((SELECT id FROM events WHERE name = 'Ecology'), 'Population Dynamics', NULL, 'The Allee effect describes:', '["A negative density dependence in population growth", "The impact of competition on carrying capacity", "The maximum reproductive potential of an organism", "A positive density dependence in population growth at low population sizes"]'::jsonb, 3, 'A positive density dependence in population growth at low population sizes', NULL, 'medium', 'multiple_choice', 1, 'Badger Invitational 2025', false),
  ((SELECT id FROM events WHERE name = 'Ecology'), 'Landscape Ecology', NULL, 'In the context of landscape ecology, what is meant by "percolation threshold"?', '["The maximum amount of habitat loss before species extinction occurs", "The point at which landscape connectivity allows for continuous species dispersal", "The rate at which water infiltrates soil in an ecosystem", "The temperature at which an ecosystem undergoes succession"]'::jsonb, 1, 'The point at which landscape connectivity allows for continuous species dispersal', NULL, 'hard', 'multiple_choice', 1, 'Badger Invitational 2025', false),
  ((SELECT id FROM events WHERE name = 'Ecology'), 'Photosynthesis', NULL, 'The C4 photosynthetic pathway is advantageous under which conditions?', '["High CO2 and low oxygen", "Low temperature and high moisture", "High temperature and low CO2", "High salinity and low nitrogen availability"]'::jsonb, 2, 'High temperature and low CO2', NULL, 'medium', 'multiple_choice', 1, 'Badger Invitational 2025', false),
  ((SELECT id FROM events WHERE name = 'Ecology'), 'Species-Area Relationship', NULL, 'Which of the following equations describes species-area relationships?', '["S = cA^z", "dN/dt = rN(1 - N/K)", "H'' = -\u03a3(pi ln pi)", "P = G + R"]'::jsonb, 0, 'S = cA^z', NULL, 'medium', 'multiple_choice', 1, 'Badger Invitational 2025', false),
  ((SELECT id FROM events WHERE name = 'Ecology'), 'Plant Ecology', NULL, 'The Janzen-Connell hypothesis suggests that:', '["Herbivory maintains plant diversity", "Seedling recruitment is suppressed near parent trees due to specialized predators", "Nutrient cycling efficiency increases with biodiversity", "Mycorrhizal associations drive forest succession"]'::jsonb, 1, 'Seedling recruitment is suppressed near parent trees due to specialized predators', NULL, 'hard', 'multiple_choice', 1, 'Badger Invitational 2025', false),
  ((SELECT id FROM events WHERE name = 'Ecology'), 'Aquatic Ecology', NULL, 'Which factor most influences primary productivity in freshwater lakes?', '["Phosphorus availability", "Iron deposition", "Wind speed", "Alkalinity"]'::jsonb, 0, 'Phosphorus availability', NULL, 'medium', 'multiple_choice', 1, 'Badger Invitational 2025', false);
INSERT INTO quiz_questions (event_id, topic, subtopic, question, options, correct_index, correct_answer_text, explanation, difficulty, question_type, points, source_tournament, ai_generated)
VALUES
  ((SELECT id FROM events WHERE name = 'Ecology'), 'Ocean Chemistry', NULL, 'What is the primary mechanism by which increased atmospheric CO2 affects ocean acidity?', '["CO2 reacts with water to form carbonic acid", "CO2 blocks sunlight, reducing photosynthesis", "CO2 enhances biological calcification", "CO2 decreases the albedo effect"]'::jsonb, 0, 'CO2 reacts with water to form carbonic acid', NULL, 'medium', 'multiple_choice', 1, 'Badger Invitational 2025', false),
  ((SELECT id FROM events WHERE name = 'Ecology'), 'Ecosystem Services', NULL, 'The Millennium Ecosystem Assessment categorized ecosystem services into which four main types?', '["Supporting, provisioning, regulating, and cultural", "Nutrient cycling, photosynthesis, decomposition, and energy flow", "Carbon sequestration, biodiversity, water filtration, and soil formation", "Primary production, secondary production, trophic transfer, and respiration"]'::jsonb, 0, 'Supporting, provisioning, regulating, and cultural', NULL, 'medium', 'multiple_choice', 1, 'Badger Invitational 2025', false),
  ((SELECT id FROM events WHERE name = 'Ecology'), 'Biodiversity', NULL, 'What does a high beta diversity value indicate?', '["High species richness within a single site", "Low turnover of species across habitats", "High turnover of species between different habitats", "Even distribution of individuals within a community"]'::jsonb, 2, 'High turnover of species between different habitats', NULL, 'medium', 'multiple_choice', 1, 'Badger Invitational 2025', false),
  ((SELECT id FROM events WHERE name = 'Ecology'), 'Fisheries Management', NULL, 'In the context of fisheries, what does maximum sustainable yield (MSY) assume?', '["That fish populations do not interact with other species", "That populations grow logistically and have a fixed carrying capacity", "That harvesting does not impact reproductive success", "That marine reserves are unnecessary for conservation"]'::jsonb, 1, 'That populations grow logistically and have a fixed carrying capacity', NULL, 'medium', 'multiple_choice', 1, 'Badger Invitational 2025', false),
  ((SELECT id FROM events WHERE name = 'Ecology'), 'Biomes', NULL, 'Which biome is predicted to be most impacted by climate change in terms of biodiversity loss?', '["Tropical rainforests", "Boreal forests", "Temperate grasslands", "Deep-sea ecosystems"]'::jsonb, 2, 'Temperate grasslands', NULL, 'medium', 'multiple_choice', 1, 'Badger Invitational 2025', false),
  ((SELECT id FROM events WHERE name = 'Ecology'), 'Island Biogeography', NULL, 'What is the relationship between island size and species richness according to the theory of island biogeography?', '["Species richness decreases with increased island size", "Species richness increases with increased island size", "Island size has no impact on species richness", "Only proximity to the mainland influences species richness"]'::jsonb, 1, 'Species richness increases with increased island size', NULL, 'medium', 'multiple_choice', 1, 'Badger Invitational 2025', false),
  ((SELECT id FROM events WHERE name = 'Ecology'), 'Deep-Sea Ecosystems', NULL, 'Why do organisms living in deep-sea hydrothermal vents rely on chemosynthesis rather than photosynthesis?', '["Sunlight cannot penetrate to these depths", "There is an abundance of nutrients from surface runoff", "Deep-sea organisms lack photosynthetic pigments", "Photosynthesis is inefficient in saline environments"]'::jsonb, 0, 'Sunlight cannot penetrate to these depths', NULL, 'easy', 'multiple_choice', 1, 'Badger Invitational 2025', false),
  ((SELECT id FROM events WHERE name = 'Ecology'), 'Soil Ecology', NULL, 'What is the primary ecological role of earthworms in soil ecosystems?', '["Nitrogen fixation", "Decomposition and nutrient cycling", "Pollination", "Carbon sequestration"]'::jsonb, 1, 'Decomposition and nutrient cycling', NULL, 'easy', 'multiple_choice', 1, 'Badger Invitational 2025', false),
  ((SELECT id FROM events WHERE name = 'Ecology'), 'Diversity Indices', NULL, 'How does the Simpson Index differ from the Shannon-Wiener Index?', '["The Simpson Index emphasizes species richness over evenness", "The Shannon-Wiener Index ignores species evenness", "The Simpson Index measures only the number of species in a community", "The Shannon-Wiener Index accounts for rare species more than the Simpson Index"]'::jsonb, 3, 'The Shannon-Wiener Index accounts for rare species more than the Simpson Index', NULL, 'hard', 'multiple_choice', 1, 'Badger Invitational 2025', false),
  ((SELECT id FROM events WHERE name = 'Ecology'), 'Niche Theory', NULL, 'What is the key difference between fundamental and realized niches?', '["The fundamental niche accounts for competition, while the realized niche does not", "The realized niche is the actual space an organism inhabits due to interactions with other species", "Fundamental niches are determined by biotic factors, while realized niches are purely abiotic", "Realized niches exist only in disturbed ecosystems"]'::jsonb, 1, 'The realized niche is the actual space an organism inhabits due to interactions with other species', NULL, 'medium', 'multiple_choice', 1, 'Badger Invitational 2025', false);
INSERT INTO quiz_questions (event_id, topic, subtopic, question, options, correct_index, correct_answer_text, explanation, difficulty, question_type, points, source_tournament, ai_generated)
VALUES
  ((SELECT id FROM events WHERE name = 'Ecology'), 'Grassland Ecology', NULL, 'Which soil type is most characteristic of temperate grasslands?', '["Spodosol", "Histosol", "Mollisol", "Oxisol"]'::jsonb, 2, 'Mollisol', NULL, 'medium', 'multiple_choice', 1, 'Badger Invitational 2025', false),
  ((SELECT id FROM events WHERE name = 'Ecology'), 'Grassland Ecology', NULL, 'What primary factor limits tree growth in grasslands?', '["Low precipitation", "High herbivore diversity", "Poor soil aeration", "High nitrogen availability"]'::jsonb, 0, 'Low precipitation', NULL, 'easy', 'multiple_choice', 1, 'Badger Invitational 2025', false),
  ((SELECT id FROM events WHERE name = 'Ecology'), 'Grassland Ecology', NULL, 'C4 grasses have an advantage over C3 grasses in:', '["Cold, wet environments", "High temperature, low CO2 environments", "Nutrient-rich, shaded forests", "High-latitude tundra regions"]'::jsonb, 1, 'High temperature, low CO2 environments', NULL, 'medium', 'multiple_choice', 1, 'Badger Invitational 2025', false),
  ((SELECT id FROM events WHERE name = 'Ecology'), 'Grassland Ecology', NULL, 'Fire plays a critical role in grassland ecology because it:', '["Reduces nitrogen availability", "Encourages woody plant succession", "Maintains open landscapes by preventing tree encroachment", "Increases soil alkalinity"]'::jsonb, 2, 'Maintains open landscapes by preventing tree encroachment', NULL, 'medium', 'multiple_choice', 1, 'Badger Invitational 2025', false),
  ((SELECT id FROM events WHERE name = 'Ecology'), 'Grassland Ecology', NULL, 'The dominant grassland biome in North America is the:', '["Pampas", "Steppe", "Prairie", "Veld"]'::jsonb, 2, 'Prairie', NULL, 'easy', 'multiple_choice', 1, 'Badger Invitational 2025', false),
  ((SELECT id FROM events WHERE name = 'Ecology'), 'Grassland Ecosystems', NULL, 'Which of the following grassland regions is maintained by seasonal flooding?', '["Serengeti", "Everglades", "Llanos", "Great Plains"]'::jsonb, 2, 'Llanos', NULL, 'medium', 'multiple_choice', 1, 'Badger Invitational 2025', false),
  ((SELECT id FROM events WHERE name = 'Ecology'), 'Grassland Ecology', NULL, 'How do grasses primarily adapt to grazing pressure?', '["By producing secondary metabolites that deter herbivory", "By developing deep root systems for water access", "By growing from basal meristems rather than apical buds", "By increasing leaf thickness to minimize water loss"]'::jsonb, 2, 'By growing from basal meristems rather than apical buds', NULL, 'medium', 'multiple_choice', 1, 'Badger Invitational 2025', false),
  ((SELECT id FROM events WHERE name = 'Ecology'), 'Grassland Ecology', NULL, 'What is the primary mechanism driving species diversity in grasslands?', '["High annual precipitation", "Frequent disturbance events such as grazing and fire", "High soil nutrient levels", "Strong interspecies competition"]'::jsonb, 1, 'Frequent disturbance events such as grazing and fire', NULL, 'medium', 'multiple_choice', 1, 'Badger Invitational 2025', false),
  ((SELECT id FROM events WHERE name = 'Ecology'), 'Grassland Ecosystems', NULL, 'The Serengeti ecosystem is famous for its large-scale migration of which herbivore?', '["American bison", "Gazelle", "Przewalski''s horse", "Wildebeest"]'::jsonb, 3, 'Wildebeest', NULL, 'easy', 'multiple_choice', 1, 'Badger Invitational 2025', false),
  ((SELECT id FROM events WHERE name = 'Ecology'), 'Grassland Degradation', NULL, 'Which of the following factors is a major contributor to grassland desertification?', '["Increased native herbivore populations", "Overgrazing by livestock", "Expansion of wetlands", "Increased CO2 fertilization"]'::jsonb, 1, 'Overgrazing by livestock', NULL, 'easy', 'multiple_choice', 1, 'Badger Invitational 2025', false);
INSERT INTO quiz_questions (event_id, topic, subtopic, question, options, correct_index, correct_answer_text, explanation, difficulty, question_type, points, source_tournament, ai_generated)
VALUES
  ((SELECT id FROM events WHERE name = 'Ecology'), 'Grassland Ecosystems', NULL, 'The primary difference between tallgrass and shortgrass prairie ecosystems is:', '["Soil nitrogen availability", "Fire frequency", "Annual precipitation levels", "Presence of large herbivores"]'::jsonb, 2, 'Annual precipitation levels', NULL, 'medium', 'multiple_choice', 1, 'Badger Invitational 2025', false),
  ((SELECT id FROM events WHERE name = 'Ecology'), 'Grassland Ecology', NULL, 'What role do mycorrhizal fungi play in grassland ecosystems?', '["They fix atmospheric nitrogen", "They enhance phosphorus uptake in plant roots", "They increase soil compaction", "They promote insect pollination"]'::jsonb, 1, 'They enhance phosphorus uptake in plant roots', NULL, 'medium', 'multiple_choice', 1, 'Badger Invitational 2025', false),
  ((SELECT id FROM events WHERE name = 'Ecology'), 'Grassland Ecology', NULL, 'What is the primary adaptation that allows grasses to survive extended droughts?', '["The ability to store water in above-ground stems", "Aerenchyma tissue development", "Extensive below-ground root systems", "High transpiration rates"]'::jsonb, 2, 'Extensive below-ground root systems', NULL, 'medium', 'multiple_choice', 1, 'Badger Invitational 2025', false),
  ((SELECT id FROM events WHERE name = 'Ecology'), 'Grassland Ecology', NULL, 'Which of the following processes is most responsible for the maintenance of grassland biodiversity?', '["Primary succession", "Fire suppression", "Periodic grazing and fire disturbance", "Increased CO2 concentration in the atmosphere"]'::jsonb, 2, 'Periodic grazing and fire disturbance', NULL, 'medium', 'multiple_choice', 1, 'Badger Invitational 2025', false),
  ((SELECT id FROM events WHERE name = 'Ecology'), 'Carbon Cycling', NULL, 'Grasslands contribute significantly to global carbon cycles through:', '["Carbon fixation by fast-growing woody plants", "The deep sequestration of organic material in soils", "Increased methane emissions from herbivores", "Rapid decomposition of above-ground biomass"]'::jsonb, 1, 'The deep sequestration of organic material in soils', NULL, 'medium', 'multiple_choice', 1, 'Badger Invitational 2025', false),
  ((SELECT id FROM events WHERE name = 'Ecology'), 'Grassland Ecology', NULL, 'Which of the following best explains why beta diversity is often higher in grassland ecosystems compared to forests?', '["Grasslands experience more frequent disturbances, leading to increased species turnover.", "Forests have higher species richness, which results in higher beta diversity.", "Grassland species are highly specialized, leading to low overlap between different locations.", "Grasslands have fewer primary producers, reducing competitive exclusion and increasing diversity."]'::jsonb, 0, 'Grasslands experience more frequent disturbances, leading to increased species turnover.', NULL, 'hard', 'multiple_choice', 1, 'Badger Invitational 2025', false),
  ((SELECT id FROM events WHERE name = 'Ecology'), 'Diversity Indices', NULL, 'The Shannon-Wiener Index (H'') is commonly used to measure biodiversity. If a grassland ecosystem has an H'' value close to zero, what does this indicate?', '["High species evenness but low richness", "A dominance of a single species with very low diversity", "A perfectly even distribution of species", "High richness but low evenness"]'::jsonb, 1, 'A dominance of a single species with very low diversity', NULL, 'hard', 'multiple_choice', 1, 'Badger Invitational 2025', false),
  ((SELECT id FROM events WHERE name = 'Ecology'), 'Grassland Ecology', NULL, 'Which of the following processes contributes the most to functional redundancy in grassland biodiversity?', '["Low genetic variation within individual species populations", "Strong interspecific competition leading to niche differentiation", "Frequent herbivory reducing plant species dominance", "High niche overlap among plant species"]'::jsonb, 3, 'High niche overlap among plant species', NULL, 'hard', 'multiple_choice', 1, 'Badger Invitational 2025', false),
  ((SELECT id FROM events WHERE name = 'Ecology'), 'Species-Area Relationship', NULL, 'According to the species-area relationship (S = cA^z), what is the most likely consequence of habitat fragmentation in a temperate grassland ecosystem?', '["Loss of specialist species due to reduced available habitat", "Increase in ecosystem stability due to reduced species interactions", "Increased species richness as smaller patches provide unique microhabitats", "Lower extinction rates due to decreased competition for resources"]'::jsonb, 0, 'Loss of specialist species due to reduced available habitat', NULL, 'hard', 'multiple_choice', 1, 'Badger Invitational 2025', false),
  ((SELECT id FROM events WHERE name = 'Ecology'), 'Grassland Conservation', NULL, 'In the context of grassland biodiversity conservation, why is the introduction of non-native C4 grasses often problematic?', '["Non-native grasses increase nitrogen fixation, altering soil nutrient cycling.", "They outcompete native C3 grasses, reducing plant species diversity and ecosystem function.", "They increase CO2 sequestration, leading to changes in microbial diversity.", "Non-native grasses provide less food for herbivores, leading to trophic cascades."]'::jsonb, 1, 'They outcompete native C3 grasses, reducing plant species diversity and ecosystem function.', NULL, 'hard', 'multiple_choice', 1, 'Badger Invitational 2025', false);
INSERT INTO quiz_questions (event_id, topic, subtopic, question, options, correct_index, correct_answer_text, explanation, difficulty, question_type, points, source_tournament, ai_generated)
VALUES
  ((SELECT id FROM events WHERE name = 'Ecology'), 'Habitat Fragmentation', NULL, 'Which of the following is the primary cause of habitat fragmentation in temperate grasslands?', '["Fire suppression policies", "Conversion to agricultural land", "Increased precipitation due to climate change", "Decline in herbivore populations"]'::jsonb, 1, 'Conversion to agricultural land', NULL, 'easy', 'multiple_choice', 1, 'Badger Invitational 2025', false),
  ((SELECT id FROM events WHERE name = 'Ecology'), 'Habitat Fragmentation', NULL, 'The "edge effect" resulting from habitat fragmentation typically leads to:', '["Increased genetic diversity in isolated populations", "Higher rates of predation and invasive species establishment", "Greater ecosystem stability and resilience", "Increased primary productivity in interior habitat zones"]'::jsonb, 1, 'Higher rates of predation and invasive species establishment', NULL, 'medium', 'multiple_choice', 1, 'Badger Invitational 2025', false),
  ((SELECT id FROM events WHERE name = 'Ecology'), 'Grassland Restoration', NULL, 'Which soil remediation technique is most effective in restoring nutrient-depleted grasslands?', '["Introduction of nitrogen-fixing plant species", "Clear-cutting of invasive woody vegetation", "Deep plowing to increase soil aeration", "Artificial wetland construction"]'::jsonb, 0, 'Introduction of nitrogen-fixing plant species', NULL, 'medium', 'multiple_choice', 1, 'Badger Invitational 2025', false),
  ((SELECT id FROM events WHERE name = 'Ecology'), 'Ecosystem Restoration', NULL, 'The introduction of keystone species into a disturbed ecosystem is an example of:', '["Passive restoration", "Ecological engineering", "Assisted migration", "Trophic rewilding"]'::jsonb, 3, 'Trophic rewilding', NULL, 'hard', 'multiple_choice', 1, 'Badger Invitational 2025', false),
  ((SELECT id FROM events WHERE name = 'Ecology'), 'Ecosystem Restoration', NULL, 'Which of the following best describes the goal of reconciliation ecology in habitat restoration?', '["Removing all human influence to restore historical ecosystem conditions", "Designing urban spaces and agricultural landscapes to support biodiversity", "Establishing strict no-use conservation zones to minimize human disturbance", "Utilizing genetically modified species to enhance ecosystem function"]'::jsonb, 1, 'Designing urban spaces and agricultural landscapes to support biodiversity', NULL, 'hard', 'multiple_choice', 1, 'Badger Invitational 2025', false),
  ((SELECT id FROM events WHERE name = 'Ecology'), 'Desertification Management', NULL, 'In response to desertification, a commonly implemented mitigation strategy involves:', '["Applying synthetic fertilizers to increase soil fertility", "Constructing windbreaks to reduce erosion and water loss", "Removing all vegetation to prevent further degradation", "Increasing groundwater extraction to support plant growth"]'::jsonb, 1, 'Constructing windbreaks to reduce erosion and water loss', NULL, 'medium', 'multiple_choice', 1, 'Badger Invitational 2025', false),
  ((SELECT id FROM events WHERE name = 'Ecology'), 'Habitat Degradation', NULL, 'Which factor contributes the most to "biotic homogenization" in degraded habitats?', '["Increased local adaptation of native species", "Expansion of invasive generalist species replacing specialists", "Reduced nutrient cycling due to lower decomposition rates", "Restoration of primary producer communities through seeding"]'::jsonb, 1, 'Expansion of invasive generalist species replacing specialists', NULL, 'hard', 'multiple_choice', 1, 'Badger Invitational 2025', false),
  ((SELECT id FROM events WHERE name = 'Ecology'), 'Restoration Techniques', NULL, 'What is the primary disadvantage of seed banks as a habitat restoration tool?', '["They reduce the genetic variability of wild plant populations", "They only store seeds of commercially valuable species", "Seeds may not germinate effectively in degraded soil conditions", "They accelerate genetic drift in natural populations"]'::jsonb, 2, 'Seeds may not germinate effectively in degraded soil conditions', NULL, 'medium', 'multiple_choice', 1, 'Badger Invitational 2025', false),
  ((SELECT id FROM events WHERE name = 'Ecology'), 'Grassland Restoration', NULL, 'Why is prescribed burning an effective restoration tool for some grassland ecosystems?', '["It increases water retention in the soil", "It removes invasive species while promoting fire-adapted native plants", "It enhances the carbon sequestration potential of the ecosystem", "It increases soil compaction, preventing erosion"]'::jsonb, 1, 'It removes invasive species while promoting fire-adapted native plants', NULL, 'medium', 'multiple_choice', 1, 'Badger Invitational 2025', false),
  ((SELECT id FROM events WHERE name = 'Ecology'), 'Restoration Techniques', NULL, 'Which of the following is a major challenge in using bioaugmentation for habitat restoration?', '["Difficulty in selecting appropriate microbial species", "Lack of available nutrients in restored soils", "High costs associated with implementing the technique", "Ineffectiveness in non-wetland ecosystems"]'::jsonb, 0, 'Difficulty in selecting appropriate microbial species', NULL, 'hard', 'multiple_choice', 1, 'Badger Invitational 2025', false);
