  ((SELECT id FROM events WHERE name = 'Meteorology'), 'Radiation and Albedo', NULL, 'Albedo is the amount of light absorbed by a surface, such as the Earth.', '["True", "False", "", ""]'::jsonb, 1, 'False', NULL, 'easy', 'true_false', 1, 'Badger Invitational 2025', false),
